#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double a, p, q, D;
        scanf("%lf %lf %lf %lf", &a, &p, &q, &D);
        double result = a * pow(p, q);
        printf("%.0lf", result * pow(10, D));
        for (int i = 0; i < D; i++) {
            result *= 10;
            int digit = (int)result;
            printf("%d", digit);
            result -= digit;
        }
        printf("\n");
    }
    return 0;
}

