const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [a, p, q, D] = readline().split(' ').map(x => parseFloat(x));
    let result = a * Math.pow(p, q);
    process.stdout.write(Math.floor(result * Math.pow(10, D)) + '');
    for (let j = 0; j < D; j++) {
        result *= 10;
        const digit = Math.floor(result);
        process.stdout.write(digit + '');
        result -= digit;
    }
    process.stdout.write('\n');
}
